<script setup>
import { useButtonListStore } from '@/stores/buttonList';
const buttonListStore = useButtonListStore();
// router.currentRoute.value.meta.savAh == 'Y';
// router.currentRoute.value.meta.exlAh == 'Y';
// router.currentRoute.value.meta.delAh == 'Y';
import router from '@/router';
import { onMounted } from 'vue';
import BaseView from '../base/BaseView';
const { t, ref, onBeforeUnmount } = BaseView();

onMounted(() => {});

// 팝업 보임 여부
const showPrintType = ref(false);

const printTypeStyle = ref({
    position: 'absolute',
    top: '0px',
    left: '0px'
});

const printButtonRef = ref(null);

const printTypeRef = ref(null);

/**
 * 1) Print 버튼을 클릭했을 때 실행
 */
function onClickPrintBtn() {
    const btn = printButtonRef.value;
    if (!btn) return;

    const rect = btn.getBoundingClientRect();
    // 원하는 위치로 style을 지정 (이 예시는 버튼 아래쪽으로)
    printTypeStyle.value = {
        position: 'absolute',
        top: rect.bottom + window.scrollY - 80 + 'px',
        left: rect.left + window.scrollX - 70 + 'px'
    };

    // 팝업 열기
    showPrintType.value = true;
}

/**
 * 2) PDF 버튼 클릭
 */
function onClickPdf() {
    alert('PDF 버튼 클릭');
    // 팝업 닫기
    showPrintType.value = false;
}

/**
 * 3) Excel 버튼 클릭
 */
function onClickExcel() {
    alert('EXCEL 버튼 클릭');
    // 팝업 닫기
    showPrintType.value = false;
}

/**
 * 4) 바깥 클릭 이벤트
 * - 팝업 열려 있을 때, 영역 밖 클릭 시 팝업 닫기
 */
function handleClickOutside(e) {
    if (!showPrintType.value) return;

    const printTypeEl = printTypeRef.value;
    const printBtnEl = printButtonRef.value;
    if (!printTypeEl || !printBtnEl) return;

    if (printTypeEl.contains(e.target) || printBtnEl.contains(e.target)) {
        return;
    }

    showPrintType.value = false;
}

function handleResize() {
    if (showPrintType.value) {
        showPrintType.value = false;
    }
}

onMounted(() => {
    window.addEventListener('click', handleClickOutside);
    window.addEventListener('resize', handleResize);
});

onBeforeUnmount(() => {
    window.removeEventListener('click', handleClickOutside);
    window.removeEventListener('resize', handleResize);
});
</script>
<style scoped lang="scss">
.print-type {
    border: 1px solid red;
    background: #fff;
    border: 1px solid #e1e6ed;
    border-radius: 4px;
    box-shadow: 0 0 1rem rgba(0, 0, 0, 0.05);

    button {
        display: block;
        width: 90px;
        height: 45px;
        font-size: 17px;
        color: #111;
        border-bottom: 1px solid #e1e6ed;

        &:last-child {
            border-bottom: 0;
        }
    }
}
</style>
